package main

import (
	"encoding/gob"
	"fmt"
	"os"
)

type UserSession struct {
	UserID   string
	Preferences map[string]interface{}
	Permissions []string
}

func main() {
	// Create a new user session
	session := &UserSession{
		UserID: "user123",
		Preferences: map[string]interface{}{
			"language": "en-US",
			"timezone": "America/New_York",
		},
		Permissions: []string{"view", "edit"},
	}

	// Serialize the session using gob encoding
	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	err := enc.Encode(session)
	if err != nil {
		fmt.Println("Error serializing session:", err)
	}

	// Save the serialized session to disk
	f, err := os.Create("session.gob")
	if err != nil {
		fmt.Println("Error creating file:", err)
	}
	defer f.Close()
	_, err = buf.WriteTo(f)
	if err != nil {
		fmt.Println("Error writing to file:", err)
	}

	// Reload the session from disk
	f, err := os.Open("session.gob")
	if err != nil {
		fmt.Println("Error opening file:", err)
	}
	defer f.Close()
	dec := gob.NewDecoder(f)
	var loadedSession UserSession
	err = dec.Decode(&loadedSession)
	if err != nil {
		fmt.Println("Error deserializing session:", err)
	}

	// Print the loaded session
	fmt.Println("Loaded session:")
	fmt.Printf("User ID: %s\n", loadedSession.UserID)
	fmt.Printf("Preferences:\n")
	for k, v := range loadedSession.Preferences {
		fmt.Printf("\t%s: %v\n", k, v)
	}
	fmt.Printf("Permissions:\n")
	for _, p := range loadedSession.Permissions {
		fmt.Printf("\t%s\n", p)
	}
}